import UIKit

// MARK: - Password Reset Models

struct PasswordResetDeepLink {
    let token: String
    let email: String?
    let expiresAt: Date?
    
    var isValid: Bool {
        guard !token.isEmpty else { return false }
        if let expiresAt = expiresAt {
            return expiresAt > Date()
        }
        return true
    }
}

// MARK: - Universal Link Parser

class UniversalLinkParser {
    
    enum DeepLinkType {
        case passwordReset(PasswordResetDeepLink)
        case unknown
    }
    
    enum ParseError: Error, LocalizedError {
        case invalidURL
        case missingToken
        case unsupportedPath
        case expiredLink
        
        var errorDescription: String? {
            switch self {
            case .invalidURL: return "The link is invalid."
            case .missingToken: return "The reset token is missing from the link."
            case .unsupportedPath: return "This link type is not supported."
            case .expiredLink: return "This password reset link has expired."
            }
        }
    }
    
    private static let supportedHosts = ["myapp.com", "www.myapp.com"]
    private static let resetPasswordPath = "/reset-password"
    
    static func parse(url: URL) -> Result<DeepLinkType, ParseError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let host = components.host,
              supportedHosts.contains(host) else {
            return .failure(.invalidURL)
        }
        
        switch components.path {
        case resetPasswordPath:
            return parsePasswordReset(from: components)
        default:
            return .failure(.unsupportedPath)
        }
    }
    
    private static func parsePasswordReset(from components: URLComponents) -> Result<DeepLinkType, ParseError> {
        let queryItems = components.queryItems ?? []
        
        guard let token = queryItems.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            return .failure(.missingToken)
        }
        
        let email = queryItems.first(where: { $0.name == "email" })?.value
        
        var expiresAt: Date?
        if let expiresString = queryItems.first(where: { $0.name == "expires" })?.value,
           let expiresInterval = TimeInterval(expiresString) {
            expiresAt = Date(timeIntervalSince1970: expiresInterval)
        }
        
        let deepLink = PasswordResetDeepLink(
            token: token,
            email: email,
            expiresAt: expiresAt
        )
        
        guard deepLink.isValid else {
            return .failure(.expiredLink)
        }
        
        return .success(.passwordReset(deepLink))
    }
}

// MARK: - Navigation Coordinator

protocol DeepLinkNavigator: AnyObject {
    func navigateToPasswordReset(with deepLink: PasswordResetDeepLink)
    func showError(_ error: Error)
}

class DeepLinkCoordinator {
    
    weak var navigator: DeepLinkNavigator?
    
    func handleUniversalLink(_ url: URL) -> Bool {
        let result = UniversalLinkParser.parse(url: url)
        
        switch result {
        case .success(let deepLinkType):
            switch deepLinkType {
            case .passwordReset(let deepLink):
                navigator?.navigateToPasswordReset(with: deepLink)
                return true
            case .unknown:
                return false
            }
        case .failure(let error):
            navigator?.showError(error)
            return false
        }
    }
}

